import React, { useEffect, useState } from 'react';
import AppLayout from '../../components/shared/AppLayout';
import LoadingSpinner from '../../components/shared/LoadingSpinner';
import api from '../../utils/api';
import { format } from 'date-fns';

const tierConfig = {
  gold: { label: '🥇 Gold', cls: 'prize-gold', order: 1 },
  silver: { label: '🥈 Silver', cls: 'prize-silver', order: 2 },
  bronze: { label: '🥉 Bronze', cls: 'prize-bronze', order: 3 },
};

export default function AdminWinners() {
  const [winners, setWinners] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    api.get('/admin/winners')
      .then(r => setWinners(r.data.winners))
      .finally(() => setLoading(false));
  }, []);

  const filtered = filter === 'all' ? winners : winners.filter(w => w.prize_tier === filter);

  const counts = {
    all: winners.length,
    gold: winners.filter(w => w.prize_tier === 'gold').length,
    silver: winners.filter(w => w.prize_tier === 'silver').length,
    bronze: winners.filter(w => w.prize_tier === 'bronze').length,
  };

  return (
    <AppLayout>
      <div className="max-w-5xl mx-auto space-y-6 animate-slide-up">
        <div>
          <h1 className="page-title">Winners</h1>
          <p className="text-charcoal-400 mt-1">All prize winners across every draw</p>
        </div>

        {/* Stats row */}
        <div className="grid grid-cols-4 gap-3">
          {[
            { key: 'all', label: 'Total', icon: '🏆' },
            { key: 'gold', label: 'Gold', icon: '🥇' },
            { key: 'silver', label: 'Silver', icon: '🥈' },
            { key: 'bronze', label: 'Bronze', icon: '🥉' },
          ].map(item => (
            <button
              key={item.key}
              onClick={() => setFilter(item.key)}
              className={`stat-card text-left transition-all ${filter === item.key ? 'border-forest-700/60 bg-forest-900/10' : ''}`}
            >
              <div className="text-xl mb-1">{item.icon}</div>
              <div className="stat-number">{counts[item.key]}</div>
              <div className="stat-label">{item.label}</div>
            </button>
          ))}
        </div>

        {/* Winners table */}
        {loading ? (
          <div className="flex justify-center py-12"><LoadingSpinner size="lg" /></div>
        ) : filtered.length === 0 ? (
          <div className="card text-center py-16">
            <div className="text-5xl mb-4">🏆</div>
            <p className="text-charcoal-300 font-medium">No winners yet</p>
            <p className="text-charcoal-500 text-sm mt-1">Run and publish a draw to see winners here</p>
          </div>
        ) : (
          <div className="card p-0 overflow-hidden">
            <table className="w-full">
              <thead className="border-b border-charcoal-800/60">
                <tr>
                  <th className="table-header">Player</th>
                  <th className="table-header">Draw</th>
                  <th className="table-header">Matches</th>
                  <th className="table-header">Matched Numbers</th>
                  <th className="table-header">Prize</th>
                  <th className="table-header">Status</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(w => {
                  const tier = tierConfig[w.prize_tier] || {};
                  return (
                    <tr key={w._id} className="table-row">
                      <td className="table-cell">
                        <div className="flex items-center gap-2">
                          <div className="w-7 h-7 rounded-full bg-forest-800 flex items-center justify-center text-xs font-bold text-forest-300">
                            {w.user_id?.name?.[0]?.toUpperCase() || '?'}
                          </div>
                          <div>
                            <div className="text-white text-sm font-medium">{w.user_id?.name || 'Unknown'}</div>
                            <div className="text-charcoal-500 text-xs">{w.user_id?.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="table-cell">
                        <div className="text-sm">{w.draw_id?.month || '—'}</div>
                        {w.draw_id?.date && (
                          <div className="text-xs text-charcoal-600">{format(new Date(w.draw_id.date), 'MMM d')}</div>
                        )}
                      </td>
                      <td className="table-cell">
                        <span className="font-mono font-bold text-white">{w.match_count}</span>
                      </td>
                      <td className="table-cell">
                        <div className="flex gap-1.5 flex-wrap">
                          {w.matched_numbers?.map((n, i) => (
                            <span key={i} className="w-7 h-7 rounded-full bg-gold-900/40 border border-gold-700/50 text-gold-400 text-xs font-mono font-bold flex items-center justify-center">
                              {n}
                            </span>
                          ))}
                        </div>
                      </td>
                      <td className="table-cell">
                        <span className={`text-xs font-bold px-2 py-0.5 rounded-full border ${tier.cls}`}>
                          {tier.label}
                        </span>
                      </td>
                      <td className="table-cell capitalize">
                        <span className={`text-xs font-medium ${
                          w.status === 'confirmed' ? 'text-forest-400' :
                          w.status === 'paid' ? 'text-gold-400' :
                          'text-charcoal-400'
                        }`}>
                          {w.status}
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </AppLayout>
  );
}
